// Title: Detection Rule Usefulness Evaluation (DOVE Model)
// Author: Sergio Albea
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
AlertInfo
| join kind=inner AlertEvidence on AlertId
| extend DateHour = bin(Timestamp, 1h)
| summarize Group_Alert_Titles = make_set(Title), Different_Detection_Sources = make_set(DetectionSource), Number_Detection_Sources = dcount(DetectionSource)
    by DateHour, AccountUpn, EmailSubject, FileName, DeviceName, RemoteIP, RemoteUrl, Application
| where Number_Detection_Sources > 1
    and Different_Detection_Sources contains "Custom detection"
    and (isnotempty(AccountUpn) or isnotempty(RemoteIP) or isnotempty(EmailSubject) or isnotempty(DeviceName) or isnotempty(RemoteUrl) or isnotempty(Application))
| order by Number_Detection_Sources desc

// Title: APT28 Kill Chain LNK to UNC to SMB
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1566.001, T1557.001 | CVE-2026-32202
// KQL Library - https://github.com/sivolko/kql-hunter
let timeframe = 7d;
let InitialAccess_LNK = DeviceProcessEvents | where TimeGenerated > ago(timeframe)
    | where InitiatingProcessCommandLine has ".lnk"
    | project DeviceId, LNK_TriggerTime = TimeGenerated, LNK_CommandLine = InitiatingProcessCommandLine;
let Execution_UNC = DeviceProcessEvents | where TimeGenerated > ago(timeframe)
    | where ProcessCommandLine matches regex @"\\\\[a-zA-Z0-9\-\.]{4,}\\\\"
    | where ProcessCommandLine has_any (".cpl", ".dll", ".exe")
    | project DeviceId, UNC_LoadTime = TimeGenerated, UNC_CommandLine = ProcessCommandLine;
let Exfiltration_SMB = DeviceNetworkEvents | where TimeGenerated > ago(timeframe)
    | where RemotePort == 445 | where not(ipv4_is_private(RemoteIP))
    | project DeviceId, SMB_ConnectTime = TimeGenerated, RemoteIP;
InitialAccess_LNK
| join kind=inner Execution_UNC on DeviceId
| where UNC_LoadTime between (LNK_TriggerTime .. (LNK_TriggerTime + 2m))
| join kind=inner Exfiltration_SMB on DeviceId
| where SMB_ConnectTime between (UNC_LoadTime .. (UNC_LoadTime + 2m))
| project DeviceId, LNK_Time = LNK_TriggerTime, UNC_Time = UNC_LoadTime, SMB_Time = SMB_ConnectTime, LNK_CommandLine, UNC_CommandLine, RemoteIP
| extend AlertTitle = "APT28 Kill Chain: LNK->UNC->SMB", Severity = "Critical", MITRE = "T1566.001->T1557.001"

// Title: Copilot Jailbreak Detected
// Author: Alex Verboon
// Source: https://www.kqlsearch.com
// MITRE ATLAS: AML.T0054
// KQL Library - https://github.com/sivolko/kql-hunter
CopilotActivity
| where RecordType == "CopilotInteraction"
| extend LLMData = parse_json(LLMEventData)
| mv-expand Message = LLMData.Messages
| extend JailbreakDetected = tobool(Message.JailbreakDetected)
| where JailbreakDetected == true
| order by TimeGenerated desc

// Title: Git Abuse High Fidelity
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
let GitConfig = DeviceProcessEvents
    | where ProcessCommandLine has "git config --local" | where ProcessCommandLine has_any ("user.name", "user.email")
    | project DeviceId, DeviceName, AccountName, GitConfigTime = Timestamp, GitConfigCmd = ProcessCommandLine;
let GitAmend = DeviceProcessEvents
    | where ProcessCommandLine has "git commit" | where ProcessCommandLine has "--amend"
    | project DeviceId, AmendTime = Timestamp, AmendCmd = ProcessCommandLine;
let GitPush = DeviceProcessEvents
    | where ProcessCommandLine has "git push" | where ProcessCommandLine has_any ("-f", "--force", "-uf", "--force-with-lease")
    | project DeviceId, PushTime = Timestamp, PushCmd = ProcessCommandLine;
let TimeChange = DeviceProcessEvents
    | where FileName in~ ("cmd.exe", "powershell.exe") | where ProcessCommandLine has_any ("date ", "time ", "Set-Date")
    | project DeviceId, TimeChangeTime = Timestamp, TimeChangeCmd = ProcessCommandLine;
GitConfig | join kind=inner GitAmend on DeviceId | join kind=inner GitPush on DeviceId | join kind=leftouter TimeChange on DeviceId
| where AmendTime between (GitConfigTime .. GitConfigTime + 30m)
| where PushTime between (AmendTime .. AmendTime + 30m)
| where isempty(TimeChangeTime) or TimeChangeTime between (GitConfigTime - 15m .. PushTime + 15m)
| project DeviceName, AccountName, GitConfigTime, GitConfigCmd, AmendTime, AmendCmd, PushTime, PushCmd, TimeChangeTime, TimeChangeCmd
| order by PushTime desc

// Title: Privileged RDP Session Source Mismatch
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1078, T1021.001
// KQL Library - https://github.com/sivolko/kql-hunter
let PrivUserPattern = @"sys[ae]\.[a-z]+";
let ExcludedDomains = dynamic(["nt service","font driver host","window manager","nt authority"]);
let DetectionWindow = 1h; let LookbackWindow = 1d;
let DeviceIPs = DeviceNetworkEvents | where Timestamp > ago(LookbackWindow) | where isnotempty(DeviceName) | where LocalIP != "0.0.0.0"
    | project DeviceIP_Timestamp = Timestamp, DeviceName, LocalIP;
let PrivLogons = DeviceLogonEvents | where Timestamp > ago(DetectionWindow) | where LogonType == "RemoteInteractive"
    | where AccountName matches regex PrivUserPattern | where isnotempty(RemoteIP)
    | project-rename PrivAccountName = AccountName, LogonTimestamp = Timestamp;
PrivLogons
| join kind=inner DeviceIPs on $left.RemoteIP == $right.LocalIP
| extend TimeDiff = abs(datetime_diff('second', LogonTimestamp, DeviceIP_Timestamp))
| where TimeDiff < 3600
| summarize arg_min(TimeDiff, *) by LogonTimestamp, DeviceName, PrivAccountName, RemoteIP
| join kind=leftouter (DeviceLogonEvents | where Timestamp > ago(LookbackWindow) | where LogonType in ("Interactive","RemoteInteractive")
    | where AccountDomain !in (ExcludedDomains) | summarize RecentUsers = make_set(AccountName, 3) by DeviceName) on $left.DeviceName1 == $right.DeviceName
| where isnotempty(RecentUsers)
| mv-expand RecentUser = RecentUsers to typeof(string)
| extend Short1 = extract(@"\.(.+)$", 1, PrivAccountName)
| extend Short2 = strcat(substring(RecentUser,0,1), extract(@"\.(.+)$",1,RecentUser))
| summarize MatchFound = countif(Short2 has Short1), arg_max(LogonTimestamp,*) by DeviceName1, PrivAccountName
| where MatchFound == 0
| project LogonTimestamp, DeviceName, PrivAccountName, RemoteIP, RecentUsers

// Title: SharePoint Phishing Click + Verification Code + Suspicious Login
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1566 (Phishing)
// KQL Library - https://github.com/sivolko/kql-hunter
let lookback = 1h;
let PhishClicks = UrlClickEvents
| where TimeGenerated > ago(lookback)
| where ActionType == "ClickAllowed"
| where Url has_any ("sharepoint.com", "onedrive.com")
| where IsClickedThrough == true
| project AccountId, ClickTime = TimeGenerated, PhishUrl = Url, IPAddress;
let OTPEmails = EmailEvents
| where TimeGenerated > ago(lookback)
| where Subject has_any ("verification code", "one-time", "OTP", "confirm your")
| project RecipientEmailAddress, OTPTime = TimeGenerated, Subject;
let SuspiciousSignIns = EntraIdSignInEvents
| where TimeGenerated > ago(lookback)
| where ErrorCode == 0
| where RiskLevelDuringSignIn >= 50
| project AccountUpn, SignInTime = TimeGenerated, IPAddress, RiskLevelDuringSignIn;
PhishClicks
| join kind=inner OTPEmails on $left.AccountId == $right.RecipientEmailAddress
| where OTPTime between (ClickTime .. ClickTime + 30m)
| join kind=inner SuspiciousSignIns on $left.AccountId == $right.AccountUpn
| where SignInTime between (OTPTime .. OTPTime + 30m)
| project ClickTime, OTPTime, SignInTime, AccountId, PhishUrl, RiskLevelDuringSignIn

// Title: Post-Phishing URL Click Suspicious Sign-Ins
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
let lookback = 24h;
let PhishClicks = UrlClickEvents
| where TimeGenerated > ago(lookback)
| where ActionType has_any ("ClickAllowed", "ClickBlocked")
| where IsClickedThrough == true
| project AccountId, ClickTime = TimeGenerated, ClickUrl = Url, ClickIP = IPAddress;
PhishClicks
| join kind=inner (
    EntraIdSignInEvents
    | where TimeGenerated > ago(lookback)
    | where ErrorCode == 0
    | project AccountUpn, SignInTime = TimeGenerated, SignInIP = IPAddress, UserAgent, RiskLevelDuringSignIn
) on $left.AccountId == $right.AccountUpn
| where SignInTime between (ClickTime .. ClickTime + 60m)
| where SignInIP != ClickIP
| project ClickTime, SignInTime, AccountId, ClickUrl, ClickIP, SignInIP, UserAgent, RiskLevelDuringSignIn
| order by SignInTime desc

// Title: High-Privilege Takeover: Agent ID Administrator Role Abuse
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1098 - Account Manipulation
// KQL Library - https://github.com/sivolko/kql-hunter
AuditLogs
| where TimeGenerated > ago(90d)
| where OperationName has_any ("Add member to role", "Add eligible member to role")
| extend TargetRole = tostring(TargetResources[0].displayName)
| extend Initiator = tostring(InitiatedBy.user.userPrincipalName)
| extend TargetUser = tostring(TargetResources[0].userPrincipalName)
| where TargetRole has_any ("Agent", "Administrator", "Global")
| project TimeGenerated, Initiator, TargetUser, TargetRole, OperationName, Result
| order by TimeGenerated desc

// Title: New Tenant Allow/Block List (TABL) Entry
// Author: Jay Kerai
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
CloudAppEvents
| where TimeGenerated > ago(30d)
| where ActionType has_any ("TenantAllowBlockListEntryCreated", "TenantAllowBlockListEntryModified")
| extend EntryValue = tostring(RawEventData.Value)
| extend EntryType = tostring(RawEventData.ListType)
| extend EntryAction = tostring(RawEventData.Action)
| extend Actor = tostring(AccountDisplayName)
| project TimeGenerated, Actor, EntryType, EntryValue, EntryAction, IPAddress
| order by TimeGenerated desc

// Title: Detect Potential Malicious Emails via InternetMessageId Dates
// Author: Sergio Albea
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
EmailEvents
| where Timestamp > ago(7d)
| where isnotempty(InternetMessageId)
| extend MsgIdDate = extract(@"(\d{8}|\d{6}|\d{4})", 0, InternetMessageId)
| extend MsgIdYear = toint(substring(MsgIdDate, 0, 4))
| where MsgIdYear < 2020 or MsgIdYear > year(now()) + 1
| join kind=leftouter (EmailUrlInfo | where Timestamp > ago(7d) | summarize UrlCount = count(), Urls = make_set(Url, 5) by NetworkMessageId) on NetworkMessageId
| project Timestamp, SenderFromAddress, RecipientEmailAddress, Subject, InternetMessageId, MsgIdDate, MsgIdYear, UrlCount, Urls, DeliveryAction
| order by Timestamp desc

// Title: Detect Microsoft Shared File Messages via ODSPNOTIFY
// Author: Sergio Albea
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
EmailEvents
| where Timestamp > ago(30d)
| where InternetMessageId has "odspnotify"
| where Subject has_any ("shared", "invited", "has shared", "gave you access")
| join kind=leftouter (EmailUrlInfo | where Timestamp > ago(30d) | where Url has_any ("sharepoint.com","onedrive.com") | summarize ShareUrls = make_set(Url,5) by NetworkMessageId) on NetworkMessageId
| project Timestamp, SenderFromAddress, RecipientEmailAddress, Subject, ShareUrls, DeliveryAction
| order by Timestamp desc

// Title: Sentinel Watchlists Overview
// Author: Alex Verboon
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
_GetWatchlist('YourWatchlistAlias')
| summarize EntryCount = count()
// To list all watchlists dynamically, use the Watchlist table:
// Watchlist
// | summarize EntryCount = count(), LastUpdated = max(TimeGenerated) by WatchlistAlias, WatchlistName
// | order by EntryCount desc

// Title: Copilot Agents Sharing Activity
// Author: Alex Verboon
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
CloudAppEvents
| where TimeGenerated > ago(30d)
| where ActionType has_any ("AgentShared", "CopilotAgentShared", "ShareAgent")
| extend AgentName = tostring(RawEventData.AgentName)
| extend SharedWith = tostring(RawEventData.SharedWith)
| extend ShareScope = tostring(RawEventData.ShareScope)
| join kind=leftouter (IdentityInfo | summarize arg_max(TimeGenerated,*) by AccountUpn | project AccountUpn, Department, JobTitle) on $left.AccountId == $right.AccountUpn
| project TimeGenerated, AccountDisplayName, Department, AgentName, SharedWith, ShareScope, IPAddress
| order by TimeGenerated desc

// Title: Copilot Agents Allowed Agent Types
// Author: Alex Verboon
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
CloudAppEvents
| where TimeGenerated > ago(30d)
| where ActionType has_any ("AgentTypeAllowed", "CopilotAgentConfiguration", "AgentPolicyUpdated")
| extend AgentType = tostring(RawEventData.AgentType)
| extend PolicyAction = tostring(RawEventData.Action)
| summarize Count = count(), LastSeen = max(TimeGenerated) by AgentType, PolicyAction, AccountDisplayName
| order by Count desc

// Title: Copilot Agents User Access
// Author: Alex Verboon
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
CloudAppEvents
| where TimeGenerated > ago(30d)
| where ActionType has_any ("AgentAccessGranted", "CopilotAgentUserAccess", "AgentUserAdded")
| extend AgentName = tostring(RawEventData.AgentName)
| extend GrantedToUser = tostring(RawEventData.GrantedTo)
| join kind=leftouter (IdentityInfo | summarize arg_max(TimeGenerated,*) by AccountUpn | project AccountUpn, Department, JobTitle, City) on $left.AccountId == $right.AccountUpn
| project TimeGenerated, AccountDisplayName, Department, AgentName, GrantedToUser, IPAddress
| order by TimeGenerated desc

// Title: Unusual User Agent from Registered Device Bypassing Conditional Access
// Author: Jose Sebastian Canos
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
let lookback = 14d;
let BaselineWindow = 30d;
let KnownUserAgents = SigninLogs
    | where TimeGenerated between (ago(BaselineWindow) .. ago(lookback))
    | where isnotempty(tostring(DeviceDetail.deviceId))
    | summarize BaselineUAs = make_set(tostring(UserAgent), 20) by UserPrincipalName;
SigninLogs
| where TimeGenerated > ago(lookback)
| where isnotempty(tostring(DeviceDetail.deviceId))
| where ConditionalAccessStatus != "failure"
| extend DeviceTrust = tostring(DeviceDetail.trustType)
| join kind=leftouter KnownUserAgents on UserPrincipalName
| where not(set_has_element(BaselineUAs, tostring(UserAgent)))
| summarize UnknownUAs = make_set(tostring(UserAgent),5), Count = count() by UserPrincipalName, DeviceTrust
| where Count >= 3
| order by Count desc

// Title: Defender RedSun Named Pipe Detection Correlated to AV
// Author: Jay Kerai
// Source: https://www.kqlsearch.com
// MITRE: T1055 - Process Injection
// KQL Library - https://github.com/sivolko/kql-hunter
let NamedPipeEvents = DeviceEvents
| where Timestamp > ago(7d)
| where ActionType == "NamedPipeEvent"
| where AdditionalFields has_any ("redsun", "RedSun", "\\pipe\\")
| project DeviceId, DeviceName, PipeTime = Timestamp, PipeName = tostring(parse_json(AdditionalFields).PipeName);
NamedPipeEvents
| join kind=inner (
    DeviceProcessEvents
    | where Timestamp > ago(7d)
    | where InitiatingProcessFileName has_any ("MsMpEng", "antivirus", "defender")
    | project DeviceId, AVTime = Timestamp, AVProcess = FileName, AVCmd = ProcessCommandLine
) on DeviceId
| where AVTime between (PipeTime - 5m .. PipeTime + 5m)
| project DeviceName, PipeTime, PipeName, AVTime, AVProcess, AVCmd
| order by PipeTime desc

// Title: Defender RedSun TieringEngineService in AppData
// Author: Jay Kerai
// Source: https://www.kqlsearch.com
// MITRE: T1036 - Masquerading
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceFileEvents
| where Timestamp > ago(7d)
| where FileName has_any ("TieringEngineService", "tieringengineservice")
| where FolderPath has_any ("AppData", "\\appdata\\")
| where ActionType in ("FileCreated", "FileModified")
| project Timestamp, DeviceName, FolderPath, FileName, SHA256, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessAccountName
| order by Timestamp desc

// Title: Suspicious Device Code Authentication
// Author: Jose Sebastian Canos
// Source: https://www.kqlsearch.com
// MITRE: T1566.002 - Spearphishing Link
// KQL Library - https://github.com/sivolko/kql-hunter
let lookback = 7d;
let DeviceCodeSignins = SigninLogs
| where TimeGenerated > ago(lookback)
| where AuthenticationProtocol == "deviceCode" or ClientAppUsed == "Device Login"
| where ResultType == "0"
| project UPN = UserPrincipalName, SignInTime = TimeGenerated, IPAddress, Location, DeviceId = tostring(DeviceDetail.deviceId);
DeviceCodeSignins
| where isempty(DeviceId)
| summarize Count = count(), IPs = make_set(IPAddress, 10), Locations = make_set(Location, 10) by UPN, bin(SignInTime, 1h)
| where Count >= 2
| order by Count desc

// Title: Users Authenticating with the MFA Companion App
// Author: Nathan Hutchinson
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
SigninLogs
| where TimeGenerated > ago(30d)
| where ResultType == "0"
| where isnotempty(AuthenticationDetails)
| mv-expand AuthStep = parse_json(AuthenticationDetails)
| extend MFAMethod = tostring(AuthStep.authenticationMethod)
| where MFAMethod has_any ("Companion", "companion app", "MicrosoftAuthenticator")
| summarize SignInCount = count(), LastSeen = max(TimeGenerated) by UserPrincipalName, MFAMethod
| order by SignInCount desc

// Title: Detect TLS Validation Bypass via PowerShell
// Author: Sergio Albea
// Source: https://www.kqlsearch.com
// MITRE: T1562 - Impair Defenses
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where FileName in~ ("powershell.exe", "pwsh.exe")
| where ProcessCommandLine has_any (
    "ServerCertificateValidationCallback",
    "[System.Net.ServicePointManager]::ServerCertificateValidationCallback",
    "SkipCertificateCheck",
    "[System.Net.ServicePointManager]::SecurityProtocol",
    "CertificatePolicy",
    "TrustAllCertsPolicy"
)
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine
| order by Timestamp desc

// Title: Audit Claude AI Behavior on Endpoints
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has_any ("claude", "anthropic", "claude.exe", "claude-code")
    or FileName has_any ("claude", "anthropic")
| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName
| union (
    DeviceFileEvents
    | where Timestamp > ago(30d)
    | where FolderPath has_any ("claude", "anthropic", ".claude")
    | project Timestamp, DeviceName, AccountName = InitiatingProcessAccountName, FileName, FolderPath, ActionType
)
| order by Timestamp desc

// Title: Git Force Push Detection
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has "git push"
| where ProcessCommandLine has_any ("-f", "--force", "--force-with-lease", "-uf")
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine
| extend Repo = extract(@"origin\s+(\S+)", 1, ProcessCommandLine)
| order by Timestamp desc

// Title: Git Commit --amend --no-verify
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has "git commit"
| where ProcessCommandLine has "--amend"
| where ProcessCommandLine has "--no-verify"
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName
| order by Timestamp desc

// Title: Batch Git Abuse Detection
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where InitiatingProcessFileName in~ ("cmd.exe", "powershell.exe")
| where ProcessCommandLine has "git"
| where ProcessCommandLine has_any ("--amend", "--force", "config --local", "--no-verify", "reset --hard")
| summarize AbuseCount = count(), Commands = make_set(ProcessCommandLine, 10) by DeviceId, DeviceName, AccountName, bin(Timestamp, 10m)
| where AbuseCount >= 2
| order by AbuseCount desc

// Title: Defense Evasion Git Time Change
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// MITRE: T1070 - Indicator Removal
// KQL Library - https://github.com/sivolko/kql-hunter
let GitCommits = DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has "git commit"
| project DeviceId, CommitTime = Timestamp;
let TimeChanges = DeviceProcessEvents
| where Timestamp > ago(30d)
| where FileName in~ ("cmd.exe", "powershell.exe")
| where ProcessCommandLine has_any ("date ", "time ", "Set-Date", "w32tm")
| project DeviceId, DeviceName, AccountName, ChangeTime = Timestamp, ChangeCmd = ProcessCommandLine;
TimeChanges
| join kind=inner GitCommits on DeviceId
| where CommitTime between (ChangeTime - 5m .. ChangeTime + 5m)
| project DeviceName, AccountName, ChangeTime, ChangeCmd, CommitTime
| order by ChangeTime desc

// Title: Defense Evasion Git Config Masquerade
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// MITRE: T1036 - Masquerading
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where ProcessCommandLine has "git config"
| where ProcessCommandLine has_any ("user.name", "user.email")
| extend TargetIdentity = extract(@"(user\.(?:name|email))\s+(.+)", 2, ProcessCommandLine)
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, TargetIdentity, InitiatingProcessFileName
| order by Timestamp desc

// Title: Correlation Git and VS Code Task Abuse
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where InitiatingProcessFileName in~ ("code.exe", "code", "Code - OSS")
| where ProcessCommandLine has "git"
| where ProcessCommandLine has_any ("--amend", "--force", "config --local", "--no-verify", "reset", "rebase")
| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine
| order by Timestamp desc

// Title: IFEO Unauthorized Debugger Registration
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1546.012 - Event Triggered Execution: Image File Execution Options Injection
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceRegistryEvents
| where Timestamp > ago(30d)
| where RegistryKey has @"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options"
| where RegistryValueName in~ ("Debugger", "GlobalFlag")
| where ActionType in ("RegistryValueSet", "RegistryKeyCreated")
| extend DebuggerValue = tostring(RegistryValueData)
| where isnotempty(DebuggerValue)
| where not(DebuggerValue has_any ("vsjitdebugger", "ntsd", "windbg"))
| project Timestamp, DeviceName, AccountName = InitiatingProcessAccountName, RegistryKey, RegistryValueName, DebuggerValue, InitiatingProcessFileName, InitiatingProcessCommandLine
| order by Timestamp desc

// Title: macOS Suspicious Shell or Process from Browser
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// MITRE: T1203 - Exploitation for Client Execution
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceProcessEvents
| where Timestamp > ago(30d)
| where OSPlatform == "macOS"
| where InitiatingProcessFileName in~ ("Google Chrome", "Safari", "Firefox", "Microsoft Edge", "Chromium")
| where FileName in~ ("bash", "sh", "zsh", "python", "python3", "perl", "ruby", "osascript", "curl", "wget")
| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine
| order by Timestamp desc

// Title: Node C2 Polinder Detection
// Author: Ali Hussein
// Source: https://www.kqlsearch.com
// MITRE: T1071 - Application Layer Protocol
// KQL Library - https://github.com/sivolko/kql-hunter
DeviceNetworkEvents
| where Timestamp > ago(7d)
| where InitiatingProcessFileName in~ ("node.exe", "node", "nodejs")
| where not(ipv4_is_private(RemoteIP))
| where RemotePort !in (80, 443, 8080, 8443)
| extend ProcessDir = extract(@"(.+)\\[^\\]+$", 1, InitiatingProcessFolderPath)
| where ProcessDir has_any ("AppData", "Temp", "Downloads", "Users")
| project Timestamp, DeviceName, RemoteIP, RemotePort, RemoteUrl, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessFolderPath
| order by Timestamp desc

// Title: Microsoft Defender Cloud App Discovery to Log Analytics
// Author: Benjamin Zulliger
// Source: https://www.kqlsearch.com
// KQL Library - https://github.com/sivolko/kql-hunter
// Query the custom table populated by Cloud App Discovery export
CloudAppRiskCatalog_CL
| where TimeGenerated > ago(30d)
| extend AppName = tostring(parse_json(RawData).AppName)
| extend RiskScore = toint(parse_json(RawData).RiskScore)
| extend Category = tostring(parse_json(RawData).Category)
| extend Users = toint(parse_json(RawData).Users)
| extend Transactions = toint(parse_json(RawData).Transactions)
| where RiskScore >= 5
| summarize AppCount = count(), MaxRisk = max(RiskScore), TotalUsers = sum(Users) by Category
| order by TotalUsers desc
